#!/usr/bin/env node
/**
 * gen-toc — insert/refresh an auto-generated Table of Contents in long markdown docs.
 *
 * Self-maintaining: re-run it any time headings change. It rewrites only the block
 * between the markers, so prose is never touched. Pure node, no deps.
 *
 *   node docs/bin/gen-toc.mjs           # refresh every docs/**.md over the line threshold
 *   node docs/bin/gen-toc.mjs --check   # exit 1 if any TOC is stale (for CI / a hook)
 *   node docs/bin/gen-toc.mjs path.md…  # only these files
 *
 * How it decides where to put the TOC:
 *  - if the file already has the <!-- TOC --> … <!-- /TOC --> markers, it refreshes in place;
 *  - else it inserts a fresh block right after the first H1 (the title) + its lead blurb.
 * Docs at/under MIN_LINES are skipped (a short doc doesn't need a TOC) unless named explicitly.
 */

import { readFileSync, writeFileSync, readdirSync, statSync } from 'node:fs';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const DOCS_DIR = dirname(dirname(fileURLToPath(import.meta.url))); // …/docs
const MIN_LINES = 150;            // only docs longer than this get a TOC (when auto-scanning)
const START = '<!-- TOC -->';
const END = '<!-- /TOC -->';
const MARKER_NOTE = '<!-- auto-generated by docs/bin/gen-toc.mjs — do not edit by hand -->';

/** All *.md under docs/, recursively. */
function allDocs(dir = DOCS_DIR) {
  const out = [];
  for (const name of readdirSync(dir)) {
    const p = join(dir, name);
    const s = statSync(p);
    if (s.isDirectory()) { if (name !== 'bin') out.push(...allDocs(p)); }
    else if (name.endsWith('.md')) out.push(p);
  }
  return out;
}

/**
 * GitHub-style anchor slug — matches github-slugger's algorithm, which is what
 * GitHub uses to make heading anchors. ORDER MATTERS:
 *  1. lowercase;
 *  2. strip ` and any char not [a-z0-9 _-] (emoji/punctuation just VANISH — they do
 *     NOT become a separator, so the surrounding spaces remain);
 *  3. each space → a single hyphen, but DON'T collapse runs (so a removed emoji's
 *     leftover space pair becomes `--`, exactly like GitHub — getting this wrong is
 *     the classic broken-TOC-anchor bug).
 */
function slug(text) {
  return text.toLowerCase()
    .replace(/[^\w\s-]/g, '') // drop ` punctuation emoji (no replacement char)
    .replace(/\s/g, '-');     // each whitespace → one hyphen (runs preserved → -- )
}

/** Build the TOC markdown for a doc's body. Returns '' if <2 headings worth listing. */
function buildToc(body) {
  const lines = body.split('\n');
  const heads = [];
  let inFence = false;
  for (const line of lines) {
    if (/^```/.test(line)) { inFence = !inFence; continue; }
    if (inFence) continue;
    const m = /^(#{2,3})\s+(.*)$/.exec(line); // ## and ### only (H1 is the title)
    if (!m) continue;
    const level = m[1].length;               // 2 or 3
    const text = m[2].replace(/\s*#+\s*$/, '').trim();
    if (/^table of contents$/i.test(text)) continue;
    heads.push({ level, text });
  }
  if (heads.length < 2) return '';
  const slugCount = new Map();
  const rows = heads.map((h) => {
    let s = slug(h.text);
    const n = slugCount.get(s) ?? 0;          // GitHub disambiguates dupes with -1, -2…
    slugCount.set(s, n + 1);
    if (n > 0) s = `${s}-${n}`;
    const indent = h.level === 3 ? '  ' : '';
    return `${indent}- [${h.text}](#${s})`;
  });
  return `${START}\n${MARKER_NOTE}\n## Contents\n${rows.join('\n')}\n${END}`;
}

/** Insert/replace the TOC block. Returns the new content (or the same if unchanged). */
function applyToc(content) {
  const startIdx = content.indexOf(START);
  const endIdx = content.indexOf(END);
  // body = everything OUTSIDE an existing TOC block (so headings inside it don't recurse)
  let body = content;
  if (startIdx !== -1 && endIdx !== -1 && endIdx > startIdx) {
    body = content.slice(0, startIdx) + content.slice(endIdx + END.length);
  }
  const toc = buildToc(body);
  if (!toc) return content; // nothing to list

  if (startIdx !== -1 && endIdx !== -1 && endIdx > startIdx) {
    // refresh in place
    return content.slice(0, startIdx) + toc + content.slice(endIdx + END.length);
  }
  // fresh insert: after the first H1 + its immediate lead paragraph(s), before the first H2.
  const lines = content.split('\n');
  let insertAt = 0;
  // find first H1
  const h1 = lines.findIndex((l) => /^#\s+/.test(l));
  if (h1 !== -1) {
    insertAt = h1 + 1;
    // skip the lead blurb up to (but not including) the first H2 or a --- rule
    while (insertAt < lines.length && !/^##\s+/.test(lines[insertAt]) && !/^---\s*$/.test(lines[insertAt])) insertAt++;
  }
  const before = lines.slice(0, insertAt).join('\n').replace(/\s*$/, '');
  const after = lines.slice(insertAt).join('\n').replace(/^\s*/, '');
  return `${before}\n\n${toc}\n\n${after}\n`.replace(/\n{3,}/g, '\n\n');
}

// ── main ──────────────────────────────────────────────────────────────────────
const args = process.argv.slice(2);
const check = args.includes('--check');
const explicit = args.filter((a) => !a.startsWith('--'));
const targets = explicit.length
  ? explicit
  : allDocs().filter((p) => readFileSync(p, 'utf8').split('\n').length > MIN_LINES);

let changed = 0;
const stale = [];
for (const path of targets) {
  const content = readFileSync(path, 'utf8');
  const next = applyToc(content);
  if (next !== content) {
    changed++;
    stale.push(path);
    if (!check) writeFileSync(path, next);
  }
}

if (check) {
  if (stale.length) {
    console.error(`TOC out of date in ${stale.length} file(s):`);
    for (const p of stale) console.error(`  ${p}`);
    console.error('Run: node docs/bin/gen-toc.mjs');
    process.exit(1);
  }
  console.log(`TOC up to date (${targets.length} docs checked).`);
} else {
  console.log(`gen-toc: updated ${changed}/${targets.length} docs.`);
}
